Given this code:

const ctrl = new FormControl({ value: 'locked', disabled: true });
console.log(ctrl.value);
console.log(ctrl.getRawValue());

What are the two outputs?

Given this validator factory:

export function matchValues(controlName: string, matchingControlName: string): ValidatorFn {
  return (group: AbstractControl): ValidationErrors | null => {
    const control = group.get(controlName);
    const matching = group.get(matchingControlName);
    if (control?.value !== matching?.value) {
      return { mismatch: true };
    }
    return null;
  };
}

What type should the group parameter's type be declared as for correct usage?

