Given this directive:

@Directive({ selector: '[appPermission]' })
export class PermissionDirective {
  @Input() set appPermission(role: string) {
    if (!this.authService.hasRole(role)) {
      this.viewContainer.clear();
    }
  }
  constructor(private viewContainer: ViewContainerRef, private authService: AuthService) {}
}

What type of directive pattern is this?

